import sys
n = int(sys.stdin.read().strip())
if n < 2:
    print('NONE')
else:
    sieve = [True] * (n+1)
    sieve[0] = sieve[1] = False
    for i in range(2, int(n**0.5)+1):
        if sieve[i]:
            for j in range(i*i, n+1, i):
                sieve[j] = False
    primes = [i for i in range(2, n+1) if sieve[i]]
    if primes:
        print('\n'.join(map(str, primes)))
    else:
        print('NONE')

import sys
s = sys.stdin.read().strip()
stack = []
pairs = {')': '(', '}': '{', ']': '['}
for c in s:
    if c in '({[':
        stack.append(c)
